// // This module implements a 8-bit down/up counter with asynchronous reset. The counter counts down when the up_down signal is high, and counts up when the up_down signal is low. The counter resets to 0 when the reset signal is high.
module up_down_counter(
    input wire clk,
    input wire rst,
    input wire up_down,
    output reg [7:0] count
);

always @(posedge clk) begin
    if (rst) begin
        count <= 8'b00000000;
    end else begin
        if (up_down) begin
            count <= count + 1;
        end else begin
            count <= count - 1;
        end
    end
end

endmodule
